import { ipcRenderer } from "electron";
import Modal from "../../plugins/modals";
export default {
  data() {
    return {
      visible: false
    };
  },
  methods: {
    show() {
      this.visible = true;
    },
    hide() {
      this.visible = false;
    },
    closeApp() {
      ipcRenderer.send("closeApp");
    }
  },
  beforeMount() {
    Modal.EventBus.$on("reconnect-modal-show", () => {
      this.show();
    });
    Modal.EventBus.$on("reconnect-modal-hide", () => {
      this.hide();
    });
  }
};
